    { id: 7, name: 'Docker Container Security', category: 'devops' },
    { id: 8, name: 'GraphQL API Design', category: 'backend' },
    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

// Custom debounce hook. Returns the debounced value plus an `isPending`
// flag so the UI can show a "Searching..." indicator during the delay.
function useDebounce(value, delay) {
    const [debounced, setDebounced] = useState(value);
    const [isPending, setIsPending] = useState(false);

    useEffect(() => {
        // If the value already matches, nothing is pending (e.g. initial mount).
        if (value === debounced) {
            setIsPending(false);
            return;
        }

        setIsPending(true);
        const timeoutId = setTimeout(() => {
            setDebounced(value);
            setIsPending(false);
        }, delay);

        // Cleanup clears the pending timeout on every value change AND on
        // unmount, preventing both stale updates and memory leaks.
        return () => clearTimeout(timeoutId);
    }, [value, delay, debounced]);

    return [debounced, isPending];
}

// Escape regex metacharacters so special characters in the query
// (e.g. "(", "*", "[") can't throw or behave as regex operators.
function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Splits text into matching / non-matching segments and wraps matches
// in <mark> tags. Case-insensitive, handles multiple occurrences.
function highlightMatch(text, query) {
    if (!query) return text;

    const regex = new RegExp(`(${escapeRegExp(query)})`, 'gi');
    const parts = text.split(regex);

    return parts.map((part, index) =>
        regex.test(part) && part.toLowerCase() === query.toLowerCase()
            ? <mark key={index}>{part}</mark>
            : <React.Fragment key={index}>{part}</React.Fragment>
    );
}

function ResourceList() {
    const [query, setQuery] = useState('');
    const [debouncedQuery, isPending] = useDebounce(query, 300);

    // Treat whitespace-only input as empty.
    const trimmedQuery = debouncedQuery.trim();

    const filteredItems = useMemo(() => {
        if (!trimmedQuery) return ITEMS;
        const lower = trimmedQuery.toLowerCase();
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(lower)
        );
    }, [trimmedQuery]);

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Search resources..."
                aria-label="Search resources"
            />

            {isPending && <p aria-live="polite">Searching...</p>}

            {!isPending && filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, trimmedQuery)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
```

## How each requirement is met

1. **Search input** — added at the top, controlled by `query` state.
2. **Custom 300ms debounce** — `useDebounce` hook using `setTimeout`, no lodash.
3. **Case-insensitive substring filter** — `name.toLowerCase().includes(...)` in a memoized `filteredItems`.
4. **"Searching..." indicator** — the hook exposes `isPending`, true while the timeout is in flight.
5. **Empty input shows all** — when `trimmedQuery` is falsy, returns the full `ITEMS` list.
6. **Highlighting** — `highlightMatch` splits on the query and wraps matches in `<mark>`.
7. **"No results found"** — shown when the filtered list is empty (and not mid-search, to avoid flicker).
8. **Cleanup on unmount** — `useEffect` returns `clearTimeout`, which runs on unmount and before each re-run.
9. **Edge cases** — `.trim()` handles whitespace-only input; `escapeRegExp` prevents regex errors from special characters like `(`, `*`, `[`.

## A couple of notes on choices

- I gate the "No results found" message behind `!isPending` so it doesn't flash while the user is still typing — otherwise you'd briefly see "No results" before the debounced query catches up.
- The `regex.test(part)` check inside `highlightMatch` is paired with a `toLowerCase()` equality check. Because the regex has the `g` flag, `.test()` is stateful (it advances `lastIndex`), so the explicit string comparison is what actually decides whether a segment is a match — this avoids the classic `g`-flag `lastIndex` bug producing inconsistent highlights.
- If you later need to match against `category` too, just extend the `filter` and `highlightMatch` calls accordingly.

